export function warmHealthEngineRuntime() {
  if (healthEngineRuntimeWarmSummary) {
    return healthEngineRuntimeWarmSummary;
  }

  const warmState = warmLocalMedicalCorpus(medicalKnowledgeBase);
  const graphWarmState = warmKnowledgeGraphStore();
  healthEngineRuntimeWarmSummary = {
    ready: true,
    corpusSize: medicalKnowledgeBase.length,
    cacheHit: Boolean(warmState?.cacheHit),
    graphReady: graphWarmState?.ready === true,
    graphPatientCount: Number(graphWarmState?.patientCount || 0)
  };

  return healthEngineRuntimeWarmSummary;
}

function isPromptOnlyAnalyzeIsolation(input = {}) {
  return String(input?.analysisIsolation || input?.isolationMode || "").trim().toLowerCase() === "prompt-only";
}

async function hydrateAnalyzeInputFromLocalStores(input = {}) {
  if (!input || typeof input !== "object" || Array.isArray(input) || input.localStoreHydrated === true) {
    return input;
  }

  if (isPromptOnlyAnalyzeIsolation(input)) {
    return {
      ...input,
      profile: sanitizeProfile(input.profile || {}),
      conversationHistory: normalizeHistory(input.conversationHistory || input.history || []),
      patientRecords: input.patientRecords || input.records || null,
      patientKnowledgeGraph: input.patientKnowledgeGraph || input.knowledgeGraph || {},
      localStoreHydrated: true
    };
  }

  const patientId = String(input.patientId || "demo-patient");
  const sanitizedProfile = sanitizeProfile(input.profile || {});
  const hasInjectedHistory = Array.isArray(input.conversationHistory) || Array.isArray(input.history);
  const hasInjectedProfile = Boolean(
    sanitizedProfile.name
    || sanitizedProfile.age
    || sanitizedProfile.conditions.length
    || sanitizedProfile.medications.length
    || sanitizedProfile.allergies.length
    || sanitizedProfile.baselineBp
    || sanitizedProfile.gender
    || sanitizedProfile.notes
  );
  const hasInjectedRecords = Boolean(
    input.patientRecords
    && typeof input.patientRecords === "object"
    && !Array.isArray(input.patientRecords)
  ) || Boolean(
    input.records
    && typeof input.records === "object"
    && !Array.isArray(input.records)
  );
  const hasInjectedKnowledgeGraph = Boolean(
    input.patientKnowledgeGraph
    && typeof input.patientKnowledgeGraph === "object"
    && !Array.isArray(input.patientKnowledgeGraph)
  ) || Boolean(
    input.knowledgeGraph
    && typeof input.knowledgeGraph === "object"
    && !Array.isArray(input.knowledgeGraph)
  );
  const shouldLoadMemory = !hasInjectedHistory || !hasInjectedProfile;

  if (!shouldLoadMemory && hasInjectedRecords && hasInjectedKnowledgeGraph) {
    return {
      ...input,
      localStoreHydrated: true
    };
  }

  const explicitHistory = input.conversationHistory || input.history || [];
  const [memory, patientRecords, patientKnowledgeGraph] = await Promise.all([
    shouldLoadMemory ? loadPatientMemory(patientId).catch(() => null) : Promise.resolve(null),
    hasInjectedRecords ? Promise.resolve(null) : loadPatientDataRecords(patientId).catch(() => null),
    hasInjectedKnowledgeGraph ? Promise.resolve(null) : loadPatientKnowledgeGraph(patientId).catch(() => null)
  ]);
  const mergedProfile = memory?.profile
    ? mergeSanitizedProfiles(memory.profile, input.profile || {})
    : sanitizedProfile;
  const mergedHistory = memory?.history
    ? mergeMemoryHistory(memory.history, explicitHistory)
    : explicitHistory;

  return {
    ...input,
    profile: mergedProfile,
    conversationHistory: mergedHistory,
    patientRecords: hasInjectedRecords ? (input.patientRecords || input.records) : (patientRecords || input.patientRecords || input.records),
    patientKnowledgeGraph: hasInjectedKnowledgeGraph ? (input.patientKnowledgeGraph || input.knowledgeGraph) : (patientKnowledgeGraph || input.patientKnowledgeGraph || input.knowledgeGraph),
    localStoreHydrated: true
  };
}

