function loadMemoryStore({ patientId, message = "", profile, vitals, context, conversationHistory }) {
  const normalizedHistory = mergeMemoryHistory(
    Array.isArray(conversationHistory)
      ? conversationHistory.filter((item) => item && typeof item === "object")
      : [],
    []
  );
  const totalHistoryCount = normalizedHistory.length;
  const recentHistory = normalizedHistory.slice(0, 12);
  const focusedHistory = selectRelevantMemoryHistory({
    conversationHistory: recentHistory,
    message,
    profile,
    vitals,
    context
  });
  const prioritizedHistory = mergeMemoryContextHistory(focusedHistory, recentHistory).slice(0, 8);
  const chronologicalRecentVitals = recentHistory
    .map((item) => normalizeVitals(item.vitals || item.recentReadings || {}))
    .filter(hasAnyVitals)
    .slice(0, 6);
  const chronologicalRecentProfiles = recentHistory
    .map((item) => sanitizeProfile(item.profile || item.profileSnapshot || {}))
    .filter(hasProfileSignals)
    .slice(0, 6);
  const recentRisks = dedupeResponseItems(
    prioritizedHistory
      .map((item) => cleanText(item.risk || item.latestRiskLevel))
      .filter(Boolean)
  ).slice(0, 6);
  const recentMessages = dedupeResponseItems(
    [
      ...focusedHistory.map((item) => cleanText(item.message || item.lastMessage)),
      ...prioritizedHistory.map((item) => cleanText(item.message || item.lastMessage))
    ].filter(Boolean)
  ).slice(0, 4);
  const recentVitals = prioritizedHistory
    .map((item) => normalizeVitals(item.vitals || item.recentReadings || {}))
    .filter(hasAnyVitals)
    .slice(0, 6);
  const recentProfiles = prioritizedHistory
    .map((item) => sanitizeProfile(item.profile || item.profileSnapshot || {}))
    .filter(hasProfileSignals)
    .slice(0, 6);
  const recentActions = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.actionItems) ? item.actionItems : [])
      .map((item) => cleanText(item))
      .filter(Boolean)
  ).slice(0, 4);
  const recentWarnings = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.warningSigns) ? item.warningSigns : [])
      .map((item) => cleanText(item))
      .filter(Boolean)
  ).slice(0, 4);
  const recentResponseOwners = dedupeResponseItems(
    prioritizedHistory
      .map((item) => cleanText(item.responseOwner || item.primaryRoute || ""))
      .filter(Boolean)
  ).slice(0, 4);
  const recentEvidenceRefs = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.evidenceRefs) ? item.evidenceRefs : [])
      .map((item) => cleanText(item))
      .filter(Boolean)
  ).slice(0, 6);
  const recentTriageLevels = dedupeResponseItems(
    prioritizedHistory
      .map((item) => cleanText(item.triageLevel || ""))
      .filter(Boolean)
  ).slice(0, 4);
  const recentTriageRoutes = dedupeResponseItems(
    prioritizedHistory
      .map((item) => cleanText(item.triageRoute || ""))
      .filter(Boolean)
  ).slice(0, 4);
  const recentTriageSignals = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.triageSignals) ? item.triageSignals : [])
      .map((item) => cleanText(item))
      .filter(Boolean)
  ).slice(0, 4);
  const recentReviewReasons = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.reviewReasons) ? item.reviewReasons : [])
      .map((item) => cleanText(item))
      .filter(Boolean)
  ).slice(0, 4);
  const recentDoctorQuestions = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.doctorQuestions) ? item.doctorQuestions : [])
      .map((item) => cleanText(item))
      .filter(Boolean)
  ).slice(0, 4);
  const recentPreventionFocusAreas = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.preventionFocusAreas) ? item.preventionFocusAreas : [])
      .map((item) => cleanText(item))
      .filter(Boolean)
  ).slice(0, 4);
  const recentEvidenceTitles = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.evidenceTitles) ? item.evidenceTitles : [])
      .map((item) => cleanText(item))
      .filter(Boolean)
  ).slice(0, 4);
  const recentDocumentTypes = dedupeResponseItems(
    prioritizedHistory
      .map((item) => cleanText(item.documentType || ""))
      .filter(Boolean)
  ).slice(0, 4);
  const recentDocumentMarkers = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.documentMarkers) ? item.documentMarkers : [])
      .map((item) => cleanText(item))
      .filter(Boolean)
  ).slice(0, 6);
  const recentDocumentValueHints = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.documentValueHints) ? item.documentValueHints : [])
      .map((item) => cleanText(item))
      .filter(Boolean)
  ).slice(0, 6);
  const recentSpecialistFocuses = dedupeResponseItems(
    prioritizedHistory
      .map((item) => cleanText(item.specialistFocus || item.context?.specialistFocus || ""))
      .filter(Boolean)
  ).slice(0, 4);
  const recentRiskModifiers = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.riskModifiers || item.context?.riskModifiers) ? (item.riskModifiers || item.context?.riskModifiers) : [])
      .map((item) => cleanText(item))
      .filter(Boolean)
  ).slice(0, 6);
  const recentWellnessSignals = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.wellnessSignals) ? item.wellnessSignals : flattenContextProfileSignals(item.context?.wellnessProfile, 8, 120))
      .map((item) => cleanText(item))
      .filter(Boolean)
  ).slice(0, 6);
  const recentVisitSignals = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.visitSignals) ? item.visitSignals : flattenContextProfileSignals(item.context?.visitProfile, 8, 140))
      .map((item) => cleanText(item))
      .filter(Boolean)
  ).slice(0, 6);
  const activeFocusSource = focusedHistory.length ? focusedHistory : prioritizedHistory;
  const activeFocusFamilies = dedupeResponseItems([
    ...buildMemoryFocusFamilies({ message, vitals, context }),
    ...activeFocusSource.flatMap((item) => resolveMemoryHistoryFocusFamilies(item))
  ]).slice(0, 6);
  const continuitySignals = buildMemoryContinuitySignals({
    focusedHistory,
    prioritizedHistory,
    profile,
    vitals,
    focusFamilies: activeFocusFamilies
  });
  const continuitySummary = buildMemoryContinuitySummary({
    focusedHistory,
    continuitySignals,
    recentVitals: chronologicalRecentVitals,
    focusFamilies: activeFocusFamilies
  });
  const recentRoutes = dedupeResponseItems(
    prioritizedHistory.flatMap((item) => Array.isArray(item.routes || item.latestRoutes) ? (item.routes || item.latestRoutes) : [])
  ).slice(0, 6);
  const previousVitals = selectPreviousMemoryVitals(recentHistory, vitals);
  const latestVitals = Object.fromEntries(
    Object.entries(vitals).filter(([, value]) => value !== null)
  );
  const latestContext = {
    duration: context.duration,
    severity: context.severity,
    careGoal: context.careGoal,
    supportNow: context.supportNow,
    lastMedicationTime: context.lastMedicationTime,
    redFlags: context.redFlags,
    specialistFocus: context.specialistFocus,
    specialistLens: context.specialistLens,
    riskModifiers: context.riskModifiers,
    wellnessProfile: context.wellnessProfile,
    visitProfile: context.visitProfile
  };

  return {
    patientId,
    profile,
    recentTurnCount: totalHistoryCount,
    focusedTurnCount: focusedHistory.length,
    recentRisks,
    recentMessages,
    recentVitals,
    recentProfiles,
    recentActions,
    recentWarnings,
    recentResponseOwners,
    recentEvidenceRefs,
    recentTriageLevels,
    recentTriageRoutes,
    recentTriageSignals,
    recentReviewReasons,
    recentDoctorQuestions,
    recentPreventionFocusAreas,
    recentEvidenceTitles,
    recentDocumentTypes,
    recentDocumentMarkers,
    recentDocumentValueHints,
    recentSpecialistFocuses,
    recentRiskModifiers,
    recentWellnessSignals,
    recentVisitSignals,
    focusedMessages: dedupeResponseItems(
      focusedHistory
        .map((item) => cleanText(item.message || item.lastMessage))
        .filter(Boolean)
    ).slice(0, 4),
    recentRoutes,
    activeFocusFamilies,
    continuitySignals,
    continuitySummary,
    previousVitals,
    latestProfile: chronologicalRecentProfiles[0] || sanitizeProfile({}),
    latestVitals,
    latestContext,
    summary: totalHistoryCount
      ? `Loaded ${totalHistoryCount} local memory item(s)${focusedHistory.length ? ` and prioritized ${focusedHistory.length} relevant memory match(es)` : ""}${continuitySummary ? `. ${continuitySummary}` : "."}`
      : "Loaded patient profile; no previous local conversation memory found."
  };
}

function readBooleanEnvFlag(value) {
  return /^(1|true|yes|on)$/i.test(String(value ?? "").trim());
}

function getPublicDeploymentPolicy(runtime = {}, env = process.env) {
  const publicPolicy = getEnterprisePublicDeploymentPolicy(env);
  const publicDeploymentEnabled = readBooleanEnvFlag(runtime.publicDeployment ?? publicPolicy.publicDeployment);
  const allowedOrigin = publicPolicy.allowedOrigin;
  const frameAncestors = publicPolicy.frameAncestors;
  const strictTransportSecurity = publicPolicy.strictTransportSecurity;
  const proxyTrusted = publicPolicy.trustProxy;
  const accessLogging = publicPolicy.accessLogging;
  const adminAuth = getEnterpriseAdminAuthProfile(env);
  const patientAccess = getEnterprisePatientAccessProfile(env);
  const mutationControls = getEnterpriseMutationControlProfile(env);
  const checks = [];

  if (!publicDeploymentEnabled) {
    checks.push({
      id: "public_deployment_mode",
      label: "Public deployment mode",
      status: "pass",
      detail: "Strict public-hosting checks are optional until CARE_NOVA_PUBLIC_DEPLOYMENT=true."
    });
  } else {
    checks.push({
      id: "public_deployment_mode",
      label: "Public deployment mode",
      status: "pass",
      detail: "Strict public-hosting checks are active for this deployment."
    });
    checks.push({
      id: "public_origin_policy",
      label: "Allowed origin",
      status: allowedOrigin ? "pass" : "review",
      detail: allowedOrigin
        ? `Browser API access is restricted to ${allowedOrigin}.`
        : "Set ALLOWED_ORIGIN for a shared/public deployment before release."
    });
    checks.push({
      id: "public_frame_ancestors",
      label: "Frame embedding policy",
      status: frameAncestors ? "pass" : "review",
      detail: frameAncestors
        ? `frame-ancestors is configured as ${frameAncestors}.`
        : "Set FRAME_ANCESTORS before any embedded/shared rollout."
    });
    checks.push({
      id: "public_https_transport",
      label: "HTTPS transport policy",
      status: strictTransportSecurity ? "pass" : "review",
      detail: strictTransportSecurity
        ? "Strict-Transport-Security is enabled for HTTPS hosting."
        : "Enable HSTS for shared/public deployment behind HTTPS."
    });
    checks.push({
      id: "public_proxy_identity",
      label: "Proxy-aware client identity",
      status: proxyTrusted ? "pass" : "review",
      detail: proxyTrusted
        ? "Trusted proxy headers are enabled for forwarded client identity."
        : "Enable CARE_NOVA_TRUST_PROXY behind reverse proxies or load balancers."
    });
    checks.push({
      id: "public_access_logging",
      label: "Request access logs",
      status: accessLogging ? "pass" : "review",
      detail: accessLogging
        ? "Full request access logs are enabled for enterprise operations review."
        : "Enable CARE_NOVA_ACCESS_LOG for public/shared deployment observability."
    });
    checks.push({
      id: "public_admin_auth",
      label: "Admin authentication",
      status: adminAuth.required && adminAuth.adminTokenConfigured && adminAuth.sessionSecretConfigured ? "pass" : "review",
      detail: adminAuth.required && adminAuth.adminTokenConfigured && adminAuth.sessionSecretConfigured
        ? (adminAuth.requiredByPublicDeployment
          ? "Admin authentication is enforced for public deployment."
          : "Admin authentication is configured for the shared deployment.")
        : "Configure CARE_NOVA_ADMIN_API_TOKEN and CARE_NOVA_ADMIN_SESSION_SECRET before public release."
    });
    checks.push({
      id: "public_mutation_auth",
      label: "Protected mutation policy",
      status: mutationControls.requireAdminForMutations && mutationControls.adminTokenConfigured ? "pass" : "review",
      detail: mutationControls.requireAdminForMutations && mutationControls.adminTokenConfigured
        ? (mutationControls.requiredByPublicDeployment
          ? "Protected mutation routes are enforced for public deployment."
          : "Protected mutation routes require admin verification.")
        : "Configure CARE_NOVA_REQUIRE_ADMIN_FOR_MUTATIONS or rely on public enforcement with CARE_NOVA_ADMIN_API_TOKEN before public release."
    });
    checks.push({
      id: "public_patient_access",
      label: "Patient-scoped access",
      status: patientAccess.required && patientAccess.patientAccessSecretConfigured ? "pass" : "review",
      detail: patientAccess.required && patientAccess.patientAccessSecretConfigured
        ? (patientAccess.requiredByPublicDeployment
          ? "Patient-scoped access is enforced for shared/public patient routes."
          : "Patient-scoped access is configured for protected patient routes.")
        : "Configure CARE_NOVA_PATIENT_ACCESS_SECRET before exposing patient-memory, records, graph, analyze, or realtime routes in shared deployment."
    });
  }

  const blockingChecks = checks.filter((check) => check.status !== "pass");

  return {
    checks,
    summary: {
      enabled: publicDeploymentEnabled,
      publicShareReady: blockingChecks.length === 0,
      blockingCheckCount: blockingChecks.length,
      blockingChecks: blockingChecks.map((check) => check.id),
      reviewPoints: blockingChecks.map((check) => check.detail),
      recommendedEnv: [
        "CARE_NOVA_PUBLIC_DEPLOYMENT",
        "ALLOWED_ORIGIN",
        "FRAME_ANCESTORS",
        "ENABLE_HSTS",
        "CARE_NOVA_TRUST_PROXY",
        "CARE_NOVA_ACCESS_LOG",
        "CARE_NOVA_ADMIN_API_TOKEN",
        "CARE_NOVA_ADMIN_SESSION_SECRET",
        "CARE_NOVA_ADMIN_AUTH_REQUIRED",
        "CARE_NOVA_REQUIRE_ADMIN_FOR_MUTATIONS",
        "CARE_NOVA_PATIENT_AUTH_REQUIRED",
        "CARE_NOVA_PATIENT_ACCESS_SECRET",
        "CARE_NOVA_PATIENT_HEADER"
      ]
    }
  };
}

function selectRelevantMemoryHistory({ conversationHistory = [], message = "", profile = {}, vitals = {}, context = {} }) {
  if (!Array.isArray(conversationHistory) || !conversationHistory.length) {
    return [];
  }

  const queryPhrases = buildMemoryQueryPhrases({ message, profile, vitals, context });
  const queryTokens = buildMemoryQueryTokens(queryPhrases);
  const queryFocusFamilies = buildMemoryFocusFamilies({ message, profile, vitals, context });
  const followUpRequest = isGenericLocalFollowUpRequest(message, context);
  const trendComparisonRequest = isMemoryTrendComparisonRequest(message, context);

  if (!queryPhrases.length && !queryTokens.length && !queryFocusFamilies.length) {
    return conversationHistory.slice(0, 4);
  }

  const scoredHistory = conversationHistory
    .map((item, index) => {
      const haystack = buildMemoryHistorySearchText(item);
      const haystackTokens = new Set(haystack.split(/\s+/).filter(Boolean));
      const historyFocusFamilies = resolveMemoryHistoryFocusFamilies(item);
      const phraseHits = queryPhrases.filter((phrase) => hasTerm(haystack, phrase)).length;
      const tokenHits = queryTokens.filter((token) => haystackTokens.has(token)).length;
      const entrySignals = Array.isArray(item.signals) ? item.signals : [];
      const signalHits = queryPhrases.filter((phrase) => entrySignals.some((signal) => hasTerm(signal, phrase))).length;
      const focusFamilyHits = queryFocusFamilies.filter((family) => historyFocusFamilies.includes(family)).length;
      const profileOverlap = countMemoryProfileOverlap(profile, item.profile || item.profileSnapshot || {});
      const recencyBoost = Math.max(0, 4 - index);
      const continuityBoost = followUpRequest && historyFocusFamilies.length ? Math.min(historyFocusFamilies.length, 2) : 0;
      const profileBoost = (focusFamilyHits > 0 || phraseHits > 0 || signalHits > 0) ? profileOverlap * 2 : 0;
      const score = phraseHits * 7 + signalHits * 5 + tokenHits * 2 + focusFamilyHits * 8 + profileBoost + recencyBoost + continuityBoost;

      return {
        item,
        index,
        score,
        phraseHits,
        tokenHits,
        signalHits,
        focusFamilyHits,
        hasContentMatch: phraseHits > 0 || tokenHits > 0 || signalHits > 0 || focusFamilyHits > 0
      };
    })
    .sort((left, right) => right.score - left.score || left.index - right.index);
  const directMatchScoreFloor = Math.max(3, (scoredHistory[0]?.score || 0) - 4);

  const directMatches = scoredHistory
    .filter((entry) => entry.hasContentMatch && entry.score >= directMatchScoreFloor)
    .slice(0, 4)
    .map((entry) => entry.item);

  if (directMatches.length) {
    if (trendComparisonRequest && directMatches.length < 2) {
      const trendComparisonScoreFloor = Math.max(10, directMatchScoreFloor - 12);
      const trendExpandedMatches = mergeMemoryContextHistory(
        directMatches,
        scoredHistory
          .filter((entry) => (
            entry.hasContentMatch
            && entry.focusFamilyHits > 0
            && entry.score >= trendComparisonScoreFloor
          ))
          .slice(0, 4)
          .map((entry) => entry.item)
      ).slice(0, 4);

      if (trendExpandedMatches.length > directMatches.length) {
        return trendExpandedMatches;
      }
    }

    return directMatches;
  }

  if (followUpRequest) {
    return scoredHistory
      .filter((entry) => entry.score >= 2)
      .slice(0, 4)
      .map((entry) => entry.item);
  }

  return conversationHistory.slice(0, 3);
}

function mergeMemoryContextHistory(primaryHistory = [], fallbackHistory = []) {
  const seen = new Set();
  const merged = [];

  for (const item of [...primaryHistory, ...fallbackHistory]) {
    if (!item || typeof item !== "object") {
      continue;
    }

    const key = cleanText(item.id) || `${cleanText(item.at)}:${cleanText(item.message || item.lastMessage)}`;

    if (!key || seen.has(key)) {
      continue;
    }

    seen.add(key);
    merged.push(item);
  }

  return merged;
}

function buildMemoryFocusFamilies({ message = "", profile = {}, vitals = {}, context = {}, routes = [], primaryRoute = "", requirement = null, summary = "" }) {
  const normalizedVitals = normalizeVitals(vitals);
  const routeValues = dedupeResponseItems([
    cleanText(primaryRoute).toUpperCase(),
    ...(Array.isArray(routes) ? routes.slice(0, 1).map((item) => cleanText(item).toUpperCase()).filter(Boolean) : []),
    cleanText(requirement?.expectedRoute).toUpperCase()
  ]).filter(Boolean);
  const sourceText = buildSearchText([
    message,
    context?.careGoal || "",
    context?.duration || "",
    context?.severity || "",
    Array.isArray(context?.redFlags) ? context.redFlags.join(" ") : ""
  ].join(" "));
  const focusFamilies = [];

  for (const family of memoryFocusFamilies) {
    if (family.pattern.test(sourceText)) {
      focusFamilies.push(family.id);
    }
  }

  if (Number.isFinite(normalizedVitals.systolic) || Number.isFinite(normalizedVitals.diastolic)) {
    focusFamilies.push("blood-pressure");
  }
  if (Number.isFinite(normalizedVitals.bloodSugar)) {
    focusFamilies.push("blood-sugar");
  }
  if (Number.isFinite(normalizedVitals.heartRate)) {
    focusFamilies.push("heart-circulation");
  }
  if (Number.isFinite(normalizedVitals.oxygenSaturation)) {
    focusFamilies.push("breathing-oxygen");
  }
  if (Number.isFinite(normalizedVitals.temperatureC) && normalizedVitals.temperatureC >= 38) {
    focusFamilies.push("fever-infection");
  }
  if (routeValues.includes("PHARMACY_AGENT")) {
    focusFamilies.push("medicine-dosing");
  }
  if (routeValues.includes("LABS_AGENT")) {
    focusFamilies.push("labs-reports");
  }

  return dedupeResponseItems(focusFamilies).slice(0, 8);
}

function resolveMemoryHistoryFocusFamilies(item = {}) {
  const storedFamilies = Array.isArray(item.focusFamilies)
    ? item.focusFamilies.map((entry) => buildSearchText(entry).replace(/\s+/g, "-")).filter(Boolean)
    : [];
  const computedFamilies = buildMemoryFocusFamilies({
    message: item.message || item.lastMessage || "",
    vitals: item.vitals || item.recentReadings || {},
    context: item.context || {},
    routes: Array.isArray(item.routes || item.latestRoutes) ? (item.routes || item.latestRoutes).slice(0, 1) : [],
    primaryRoute: item.primaryRoute || item.responseOwner || "",
    requirement: item.requirement || item.latestRequirement || null,
    summary: [item.summary, item.continuitySummary, item.routeSummary, item.responseFocusLabel].filter(Boolean).join(" ")
  });

  if (computedFamilies.length) {
    return computedFamilies;
  }

  if (storedFamilies.length) {
    return dedupeResponseItems(storedFamilies).slice(0, 8);
  }

  return [];
}

function countMemoryProfileOverlap(currentProfile = {}, historyProfile = {}) {
  const current = sanitizeProfile(currentProfile);
  const history = sanitizeProfile(historyProfile);
  const overlapSignals = [
    ...current.conditions.filter((item) => history.conditions.includes(item)),
    ...current.medications.filter((item) => history.medications.includes(item)),
    ...current.allergies.filter((item) => history.allergies.includes(item))
  ];

  return dedupeResponseItems(overlapSignals).slice(0, 4).length;
}

function formatMemoryFocusFamilyLabel(value = "") {
  return cleanText(value).replace(/[-_]+/g, " ").toLowerCase();
}

function flattenContextProfileSignals(value, limit = 8, itemLimit = 140) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    return [];
  }

  return dedupeResponseItems(
    Object.entries(value)
      .map(([key, entryValue]) => {
        const cleanKey = cleanText(key).replace(/[-_]+/g, " ").slice(0, 60);
        const cleanValue = cleanText(entryValue).slice(0, itemLimit);

        if (!cleanKey || !cleanValue) {
          return "";
        }

        return `${cleanKey} ${cleanValue}`;
      })
      .filter(Boolean)
  ).slice(0, limit);
}

function buildMemoryQueryPhrases({ message = "", profile = {}, vitals = {}, context = {} }) {
  const normalizedProfile = sanitizeProfile(profile);
  const normalizedVitals = normalizeVitals(vitals);
  const focusFamilies = buildMemoryFocusFamilies({ message, profile, vitals, context });
  const messagePhrases = extractMemoryTextPhrases(message, 5);
  const vitalSignals = buildMemoryVitalSignals(normalizedVitals);
  const includeProfileContinuity = !messagePhrases.length && !vitalSignals.length && !focusFamilies.length;
  const phrases = dedupeResponseItems([
    ...messagePhrases,
    ...vitalSignals,
    ...focusFamilies.map(formatMemoryFocusFamilyLabel),
    ...(includeProfileContinuity ? normalizedProfile.conditions.slice(0, 2) : []),
    ...(includeProfileContinuity ? normalizedProfile.medications.slice(0, 2) : []),
    ...(Array.isArray(context?.redFlags) ? context.redFlags : []),
    context?.specialistFocus ? formatContextLabel(context.specialistFocus) : "",
    context?.specialistLens ? `specialist lens ${formatContextLabel(context.specialistLens)}` : "",
    ...(Array.isArray(context?.riskModifiers) ? context.riskModifiers.map(formatContextLabel) : []),
    ...flattenContextProfileSignals(context?.wellnessProfile, 6, 100),
    ...flattenContextProfileSignals(context?.visitProfile, 6, 120),
    context?.careGoal ? `goal ${context.careGoal}` : "",
    context?.duration ? `duration ${context.duration}` : "",
    context?.lastMedicationTime ? `last medication ${context.lastMedicationTime}` : ""
  ]);

  return phrases.map((item) => buildSearchText(item)).filter(Boolean).slice(0, 14);
}

function buildMemoryQueryTokens(phrases = []) {
  return Array.from(new Set(
    phrases
      .flatMap((phrase) => expandMemoryFocusTokens(buildSearchText(phrase).split(/\s+/)))
      .filter((token) => token.length >= 4 && !memoryFocusStopTokens.has(token))
  ));
}

function expandMemoryFocusTokens(tokens = []) {
  return Array.from(new Set(
    (Array.isArray(tokens) ? tokens : [])
      .flatMap((token) => {
        const normalizedToken = buildSearchText(token);

        if (!normalizedToken) {
          return [];
        }

        return [
          normalizedToken,
          ...(memoryFocusTokenAliases[normalizedToken] || [])
        ];
      })
      .filter(Boolean)
  ));
}

function buildMemoryHistorySearchText(item = {}) {
  const profile = sanitizeProfile(item.profile || item.profileSnapshot || {});
  const vitals = normalizeVitals(item.vitals || item.recentReadings || {});
  const context = item.context && typeof item.context === "object" ? item.context : {};
  const routeSignals = buildMemoryRouteSignals(item.routes || item.latestRoutes, item.requirement || item.latestRequirement);
  const focusFamilies = resolveMemoryHistoryFocusFamilies(item);
  const historySegments = [
    item.searchText,
    item.message || item.lastMessage,
    item.summary,
    item.continuitySummary,
    item.routeSummary,
    item.responseFocusLabel,
    item.responseOwner,
    item.primaryIntent,
    item.primaryRoute,
    item.specialistFocus,
    item.specialistLens,
    Array.isArray(item.riskModifiers) ? item.riskModifiers.join(" ") : "",
    Array.isArray(item.wellnessSignals) ? item.wellnessSignals.join(" ") : "",
    Array.isArray(item.visitSignals) ? item.visitSignals.join(" ") : "",
    item.triageLevel,
    item.triageRoute,
    item.documentType,
    focusFamilies.map(formatMemoryFocusFamilyLabel).join(" "),
    Array.isArray(item.actionItems) ? item.actionItems.join(" ") : "",
    Array.isArray(item.warningSigns) ? item.warningSigns.join(" ") : "",
    Array.isArray(item.evidenceRefs) ? item.evidenceRefs.join(" ") : "",
    Array.isArray(item.triageSignals) ? item.triageSignals.join(" ") : "",
    Array.isArray(item.reviewReasons) ? item.reviewReasons.join(" ") : "",
    Array.isArray(item.doctorQuestions) ? item.doctorQuestions.join(" ") : "",
    Array.isArray(item.preventionFocusAreas) ? item.preventionFocusAreas.join(" ") : "",
    Array.isArray(item.evidenceTitles) ? item.evidenceTitles.join(" ") : "",
    Array.isArray(item.documentMarkers) ? item.documentMarkers.join(" ") : "",
    Array.isArray(item.documentValueHints) ? item.documentValueHints.join(" ") : "",
    Array.isArray(item.signals) ? item.signals.join(" ") : "",
    Array.isArray(item.intents || item.latestIntents) ? (item.intents || item.latestIntents).join(" ") : "",
    Array.isArray(item.routes || item.latestRoutes) ? (item.routes || item.latestRoutes).join(" ") : "",
    routeSignals.join(" "),
    profile.conditions.join(" "),
    profile.medications.join(" "),
    profile.allergies.join(" "),
    profile.notes,
    ...buildMemoryVitalSignals(vitals),
    context.duration || "",
    context.careGoal || "",
    context.severity || "",
    context.lastMedicationTime || "",
    context.specialistFocus || "",
    context.specialistLens || "",
    Array.isArray(context.riskModifiers) ? context.riskModifiers.join(" ") : "",
    ...flattenContextProfileSignals(context.wellnessProfile, 8, 120),
    ...flattenContextProfileSignals(context.visitProfile, 8, 140),
    Array.isArray(context.redFlags) ? context.redFlags.join(" ") : ""
  ];

  return buildSearchText(historySegments.filter(Boolean).join(" "));
}

function buildMemoryRouteSignals(routes = [], requirement = null) {
  const routeValues = Array.isArray(routes) ? routes : [];
  const signals = [];

  for (const route of routeValues) {
    const normalizedRoute = cleanText(route).toUpperCase();

    if (normalizedRoute === "VITALS_AGENT") {
      signals.push("vitals blood pressure pulse heart rate sugar readings");
    } else if (normalizedRoute === "PHARMACY_AGENT") {
      signals.push("medicine medication dose side effect pharmacy");
    } else if (normalizedRoute === "LABS_AGENT") {
      signals.push("labs report results panel values creatinine a1c");
    } else if (normalizedRoute === "SPECIALIST_DOCTOR_AGENT") {
      signals.push("specialist disease condition review follow up tests");
    } else if (normalizedRoute === "SCHEDULING_AGENT") {
      signals.push("appointment visit follow up schedule clinic");
    } else if (normalizedRoute === "RECORDS_AGENT") {
      signals.push("records summary history doctor note");
    } else if (normalizedRoute === "INSURANCE_AGENT") {
      signals.push("insurance appeal claim eob coverage documents");
    } else if (normalizedRoute === "WELLNESS_AGENT") {
      signals.push("wellness sleep diet stress exercise hydration");
    } else if (normalizedRoute === "ALERT_AGENT") {
      signals.push("urgent emergency warning signs chest pain breathing");
    } else if (normalizedRoute === "RAG_AGENT") {
      signals.push("general guidance symptoms review");
    }
  }

  if (requirement && typeof requirement === "object") {
    signals.push(
      cleanText(requirement.outputLabel || ""),
      cleanText(requirement.expectedRoute || ""),
      cleanText(requirement.outputType || "")
    );
  }

  return dedupeResponseItems(signals.filter(Boolean)).slice(0, 8);
}

function extractMemoryTextPhrases(value, limit = 5) {
  const text = cleanText(value).toLowerCase();

  if (!text) {
    return [];
  }

  const phrases = text
    .split(/\b(?:and|but|because|with|while|after|before|then)\b|[.!?;,:]+/i)
    .map((item) => cleanText(item))
    .filter(Boolean)
    .filter((item) => item.length >= 6);
  const keywords = text
    .split(/\s+/)
    .map((item) => item.replace(/[^a-z0-9/-]+/g, ""))
    .filter((item) => item.length >= 4)
    .filter((item) => !memoryFocusStopTokens.has(item));

  return dedupeResponseItems([...phrases, ...keywords]).slice(0, limit);
}

function buildMemoryVitalSignals(vitals = {}) {
  const normalized = normalizeVitals(vitals);
  const signals = [];

  if (Number.isFinite(normalized.systolic) && Number.isFinite(normalized.diastolic)) {
    signals.push(`bp ${normalized.systolic}/${normalized.diastolic}`);
  }
  if ((normalized.systolic || 0) >= 140 || (normalized.diastolic || 0) >= 90) {
    signals.push("high blood pressure");
  }
  if ((normalized.systolic || 999) <= 90 || (normalized.diastolic || 999) <= 60) {
    if (Number.isFinite(normalized.systolic) || Number.isFinite(normalized.diastolic)) {
      signals.push("low blood pressure");
    }
  }
  if (Number.isFinite(normalized.bloodSugar)) {
    signals.push(`blood sugar ${normalized.bloodSugar}`);
    if (normalized.bloodSugar >= 180) signals.push("high blood sugar");
    if (normalized.bloodSugar <= 70) signals.push("low blood sugar");
  }
  if (Number.isFinite(normalized.heartRate)) {
    signals.push(`heart rate ${normalized.heartRate}`);
    if (normalized.heartRate >= 100) signals.push("fast heart rate");
  }
  if (Number.isFinite(normalized.temperatureC)) {
    signals.push(`temperature ${normalized.temperatureC}`);
    if (normalized.temperatureC >= 38) signals.push("fever");
  }
  if (Number.isFinite(normalized.oxygenSaturation)) {
    signals.push(`oxygen ${normalized.oxygenSaturation}`);
    if (normalized.oxygenSaturation <= 93) signals.push("low oxygen");
  }

  return dedupeResponseItems(signals).slice(0, 8);
}

function buildMemoryContinuitySignals({ focusedHistory = [], prioritizedHistory = [], profile = {}, vitals = {}, focusFamilies = [] }) {
  const currentProfile = sanitizeProfile(profile);
  const continuityProfiles = [...focusedHistory, ...prioritizedHistory]
    .map((item) => sanitizeProfile(item.profile || item.profileSnapshot || {}))
    .filter(hasProfileSignals);
  const continuitySignals = dedupeResponseItems([
    ...currentProfile.conditions,
    ...currentProfile.medications,
    ...currentProfile.allergies,
    ...continuityProfiles.flatMap((item) => item.conditions),
    ...continuityProfiles.flatMap((item) => item.medications),
    ...continuityProfiles.flatMap((item) => item.allergies),
    ...buildMemoryVitalSignals(vitals),
    ...dedupeResponseItems(focusFamilies.map((item) => `topic ${formatMemoryFocusFamilyLabel(item)}`)).slice(0, 4),
    ...buildRecentVitalTrendKnowledgeSignals(
      prioritizedHistory
        .map((item) => normalizeVitals(item.vitals || item.recentReadings || {}))
        .filter(hasAnyVitals)
    ),
    ...focusedHistory.flatMap((item) => Array.isArray(item.signals) ? item.signals : [])
  ]);

  return continuitySignals.slice(0, 12);
}

function buildMemoryContinuitySummary({ focusedHistory = [], continuitySignals = [], recentVitals = [], focusFamilies = [] }) {
  const pieces = [];

  if (focusedHistory.length) {
    pieces.push(`Focused memory on ${focusedHistory.length} relevant prior turn(s)`);
  }

  if (focusFamilies.length) {
    pieces.push(`focus topics: ${focusFamilies.slice(0, 3).map((item) => formatMemoryFocusFamilyLabel(item)).join(", ")}`);
  }

  if (continuitySignals.length) {
    pieces.push(`continuity signals: ${continuitySignals.slice(0, 5).join(", ")}`);
  }

  const vitalTrendSignals = buildRecentVitalTrendKnowledgeSignals(recentVitals);

  if (vitalTrendSignals.length) {
    pieces.push(`trend signals: ${vitalTrendSignals.slice(0, 2).join(", ")}`);
  }

  return compactResponseText(pieces.join(". "), 220);
}

function selectPreviousMemoryVitals(recentHistory = [], currentVitals = {}) {
  const normalizedCurrent = normalizeVitals(currentVitals);
  const candidates = Array.isArray(recentHistory)
    ? recentHistory
      .map((item) => normalizeVitals(item.vitals || item.recentReadings || {}))
      .filter(hasAnyVitals)
    : [];

  if (!candidates.length) {
    return {};
  }

  const needsBloodPressure = normalizedCurrent.systolic !== null || normalizedCurrent.diastolic !== null;
  const needsGlucose = normalizedCurrent.bloodSugar !== null;
  const needsPulse = normalizedCurrent.heartRate !== null;
  const needsTemperature = normalizedCurrent.temperatureC !== null;
  const needsOxygen = normalizedCurrent.oxygenSaturation !== null;

  return candidates.find((reading) => (
    (needsBloodPressure && (reading.systolic !== null || reading.diastolic !== null))
      || (needsGlucose && reading.bloodSugar !== null)
      || (needsPulse && reading.heartRate !== null)
      || (needsTemperature && reading.temperatureC !== null)
      || (needsOxygen && reading.oxygenSaturation !== null)
  )) || candidates[0];
}

function loadRecordStore({ patientId, patientRecords, message = "" }) {
  const records = normalizePatientDataRecords(patientRecords?.records || patientRecords);
  const selectedRecordId = cleanText(patientRecords?.selectedRecordId);
  const rankedRecords = rankPatientRecordsForMessage(records, message);
  const matchedRecords = rankedRecords.filter((entry) => entry.score >= 10).map((entry) => entry.record);
  const matchedRecord = matchedRecords[0] || null;
  const activeRecord = matchedRecord || records.find((record) => record.id === selectedRecordId) || records[0] || null;
  const prioritizedRecords = matchedRecord
    ? [matchedRecord, ...matchedRecords.filter((record) => record.id !== matchedRecord.id), ...records.filter((record) => record.id !== matchedRecord.id && !matchedRecords.some((candidate) => candidate.id === record.id))]
    : activeRecord
      ? [activeRecord, ...records.filter((record) => record.id !== activeRecord.id)]
      : [];
  const signalRecords = prioritizedRecords.slice(0, 4);
  const recentRecordTypes = dedupeResponseItems(signalRecords.map((record) => record.type).filter(Boolean)).slice(0, 6);
  const recentTags = dedupeResponseItems(signalRecords.flatMap((record) => Array.isArray(record.tags) ? record.tags : [])).slice(0, 8);
  const conditions = dedupeResponseItems(signalRecords.flatMap((record) => Array.isArray(record.conditionItems) && record.conditionItems.length ? record.conditionItems : splitStoredRecordSignalText(record.conditions, 4))).slice(0, 6);
  const allergies = dedupeResponseItems(signalRecords.flatMap((record) => Array.isArray(record.allergyItems) && record.allergyItems.length ? record.allergyItems : splitStoredRecordSignalText(record.allergies, 4))).slice(0, 6);
  const medicines = dedupeResponseItems(signalRecords.flatMap((record) => Array.isArray(record.medicineNames) && record.medicineNames.length ? record.medicineNames : extractStoredRecordMedicineSignals(Array.isArray(record.medicineItems) && record.medicineItems.length ? record.medicineItems : record.medicines))).slice(0, 6);
  const vitals = dedupeResponseItems(signalRecords.flatMap((record) => Array.isArray(record.vitalItems) && record.vitalItems.length ? record.vitalItems.slice(0, 3) : [compactResponseText(record.vitals, 110)].filter(Boolean))).slice(0, 4);
  const labs = dedupeResponseItems(signalRecords.flatMap((record) => Array.isArray(record.labItems) && record.labItems.length ? record.labItems.slice(0, 3) : [compactResponseText(record.labs, 110)].filter(Boolean))).slice(0, 4);
  const episodes = dedupeResponseItems(signalRecords.map((record) => cleanText(record.episode)).filter(Boolean)).slice(0, 5);
  const followUps = dedupeResponseItems(signalRecords.flatMap((record) => Array.isArray(record.followUpItems) && record.followUpItems.length ? record.followUpItems.slice(0, 2) : [compactResponseText(record.followUp, 120)].filter(Boolean))).slice(0, 4);
  const prioritySignals = dedupeResponseItems(signalRecords.flatMap((record) => Array.isArray(record.prioritySignals) ? record.prioritySignals : [])).slice(0, 6);
  const summaries = dedupeResponseItems(signalRecords.map((record) => compactResponseText(record.summary, 180)).filter(Boolean)).slice(0, 3);
  const selectedLabel = activeRecord
    ? [activeRecord.type, activeRecord.documentCategory, activeRecord.documentName, activeRecord.episode].filter(Boolean).join(" ")
    : "";
  const selectedScore = rankedRecords.find((entry) => entry.record.id === activeRecord?.id)?.score || 0;

  return {
    patientId,
    recordCount: records.length,
    selectedRecordId: activeRecord?.id || "",
    selectedRecord: activeRecord,
    matchedRecordCount: matchedRecords.length,
    recentRecordTypes,
    recentTags,
    conditions,
    allergies,
    medicines,
    vitals,
    labs,
    episodes,
    followUps,
    prioritySignals,
    summaries,
    summary: records.length
      ? `Loaded ${records.length} local patient record(s)${selectedLabel ? matchedRecords.length ? `; matched record focus: ${selectedLabel}.` : `; no message-specific record match, active record remains ${selectedLabel}.` : "."}${summaries[0] ? ` ${summaries[0]}.` : ""}${prioritySignals.length ? ` Signals: ${prioritySignals.slice(0, 2).join(", ")}.` : ""}`
      : "Loaded local patient record store; no saved records were found."
  };
}

function toPublicRecordContext(recordContext = {}) {
  return {
    patientId: recordContext.patientId || "demo-patient",
    recordCount: Number(recordContext.recordCount || 0),
    selectedRecordId: recordContext.selectedRecordId || "",
    recentRecordTypes: Array.isArray(recordContext.recentRecordTypes) ? recordContext.recentRecordTypes.slice(0, 6) : [],
    recentTags: Array.isArray(recordContext.recentTags) ? recordContext.recentTags.slice(0, 8) : [],
    summary: recordContext.summary || "No local record context."
  };
}

function loadKnowledgeGraphStore({ patientId, patientKnowledgeGraph, message = "" }) {
  const graph = patientKnowledgeGraph && typeof patientKnowledgeGraph === "object" ? patientKnowledgeGraph : {};
  const facts = normalizeKnowledgeGraphFacts(graph.facts);
  const rankedFacts = rankKnowledgeGraphFactsForMessage(facts, message);
  const activeFacts = rankedFacts.filter((entry) => entry.score > 0).map((entry) => entry.fact);
  const signalFacts = (activeFacts.length ? activeFacts : rankedFacts.map((entry) => entry.fact)).slice(0, 8);
  const conditions = dedupeResponseItems(facts.filter((fact) => fact.type === "condition").map((fact) => fact.value)).slice(0, 6);
  const medicines = dedupeResponseItems(facts.filter((fact) => fact.type === "medicine").map((fact) => fact.value)).slice(0, 6);
  const allergies = dedupeResponseItems(facts.filter((fact) => fact.type === "allergy").map((fact) => fact.value)).slice(0, 4);
  const labs = dedupeResponseItems(facts.filter((fact) => fact.type === "lab").map((fact) => compactResponseText(fact.value, 90))).slice(0, 4);
  const vitals = dedupeResponseItems(facts.filter((fact) => fact.type === "vital").map((fact) => compactResponseText([fact.key, fact.value].filter(Boolean).join(" "), 90))).slice(0, 4);
  const safetyFlags = dedupeResponseItems(facts.filter((fact) => fact.type === "safetyFlag").map((fact) => fact.value)).slice(0, 4);
  const contextSignals = dedupeResponseItems(
    facts
      .filter((fact) => fact.type === "context")
      .map((fact) => compactResponseText([fact.key, fact.value].filter(Boolean).join(" "), 90))
  ).slice(0, 4);
  const actionItems = dedupeResponseItems(facts.filter((fact) => fact.type === "action").map((fact) => compactResponseText(fact.value, 110))).slice(0, 4);
  const warningSigns = dedupeResponseItems(facts.filter((fact) => fact.type === "warning").map((fact) => compactResponseText(fact.value, 110))).slice(0, 4);
  const focusLabels = dedupeResponseItems(facts.filter((fact) => fact.type === "focus").map((fact) => compactResponseText(fact.value, 90))).slice(0, 4);
  const responseOwners = dedupeResponseItems(facts.filter((fact) => fact.type === "responseOwner").map((fact) => compactResponseText(fact.value, 90))).slice(0, 4);
  const evidenceRefs = dedupeResponseItems(facts.filter((fact) => fact.type === "evidenceRef").map((fact) => compactResponseText(fact.value, 80))).slice(0, 6);
  const specialistFocuses = dedupeResponseItems(facts.filter((fact) => fact.type === "specialistFocus").map((fact) => compactResponseText(fact.value, 90))).slice(0, 4);
  const specialistLenses = dedupeResponseItems(facts.filter((fact) => fact.type === "specialistLens").map((fact) => compactResponseText(fact.value, 90))).slice(0, 4);
  const riskModifiers = dedupeResponseItems(facts.filter((fact) => fact.type === "riskModifier").map((fact) => compactResponseText(fact.value, 90))).slice(0, 6);
  const wellnessSignals = dedupeResponseItems(facts.filter((fact) => fact.type === "wellness").map((fact) => compactResponseText(fact.value, 110))).slice(0, 6);
  const visitSignals = dedupeResponseItems(facts.filter((fact) => fact.type === "visit").map((fact) => compactResponseText(fact.value, 120))).slice(0, 6);
  const triageRoutes = dedupeResponseItems(facts.filter((fact) => fact.type === "triageRoute").map((fact) => compactResponseText(fact.value, 90))).slice(0, 4);
  const triageSignals = dedupeResponseItems(facts.filter((fact) => fact.type === "triageSignal").map((fact) => compactResponseText(fact.value, 110))).slice(0, 4);
  const triageActions = dedupeResponseItems(facts.filter((fact) => fact.type === "triageAction").map((fact) => compactResponseText(fact.value, 110))).slice(0, 4);
  const evidenceTitles = dedupeResponseItems(facts.filter((fact) => fact.type === "evidenceTitle").map((fact) => compactResponseText(fact.value, 110))).slice(0, 4);
  const documentTypes = dedupeResponseItems(facts.filter((fact) => fact.type === "documentType").map((fact) => compactResponseText(fact.value, 90))).slice(0, 4);
  const documentMarkers = dedupeResponseItems(facts.filter((fact) => fact.type === "documentMarker").map((fact) => compactResponseText(fact.value, 90))).slice(0, 6);
  const documentValues = dedupeResponseItems(facts.filter((fact) => fact.type === "documentValue").map((fact) => compactResponseText(fact.value, 90))).slice(0, 6);
  const riskLevels = dedupeResponseItems(
    facts
      .filter((fact) => fact.type === "risk")
      .map((fact) => normalizeGraphRiskLevel(fact.key || fact.value))
      .filter(Boolean)
  ).slice(0, 3);
  const recentFacts = dedupeResponseItems(signalFacts.map((fact) => compactResponseText([fact.type, fact.value].filter(Boolean).join(" "), 90)).filter(Boolean)).slice(0, 6);
  const graphSummary = compactResponseText(cleanText(graph.summary), 180);
  const factCount = facts.length;

  return {
    patientId,
    factCount,
    nodeCount: Number(graph.nodeCount || graph.nodes?.length || 0),
    edgeCount: Number(graph.edgeCount || graph.edges?.length || 0),
    activeFactCount: activeFacts.length,
    activeFacts: signalFacts,
    conditions,
    medicines,
    allergies,
    labs,
    vitals,
    safetyFlags,
    contextSignals,
    actionItems,
    warningSigns,
    focusLabels,
    responseOwners,
    evidenceRefs,
    specialistFocuses,
    specialistLenses,
    riskModifiers,
    wellnessSignals,
    visitSignals,
    triageRoutes,
    triageSignals,
    triageActions,
    evidenceTitles,
    documentTypes,
    documentMarkers,
    documentValues,
    riskLevels,
    recentFacts,
    summary: factCount
      ? `${graphSummary || `Loaded ${factCount} persisted knowledge graph fact(s).`}${activeFacts.length ? ` Prioritized ${Math.min(activeFacts.length, signalFacts.length)} message-relevant fact(s).` : " No direct message match; using the latest persisted graph facts."}`
      : "Loaded patient knowledge graph; no persisted facts were found."
  };
}

function toPublicKnowledgeGraphContext(graphContext = {}) {
  return {
    patientId: graphContext.patientId || "demo-patient",
    factCount: Number(graphContext.factCount || 0),
    nodeCount: Number(graphContext.nodeCount || 0),
    edgeCount: Number(graphContext.edgeCount || 0),
    activeFactCount: Number(graphContext.activeFactCount || 0),
    conditions: Array.isArray(graphContext.conditions) ? graphContext.conditions.slice(0, 4) : [],
    medicines: Array.isArray(graphContext.medicines) ? graphContext.medicines.slice(0, 4) : [],
    safetyFlags: Array.isArray(graphContext.safetyFlags) ? graphContext.safetyFlags.slice(0, 4) : [],
    contextSignals: Array.isArray(graphContext.contextSignals) ? graphContext.contextSignals.slice(0, 4) : [],
    actionItems: Array.isArray(graphContext.actionItems) ? graphContext.actionItems.slice(0, 4) : [],
    warningSigns: Array.isArray(graphContext.warningSigns) ? graphContext.warningSigns.slice(0, 4) : [],
    focusLabels: Array.isArray(graphContext.focusLabels) ? graphContext.focusLabels.slice(0, 4) : [],
    responseOwners: Array.isArray(graphContext.responseOwners) ? graphContext.responseOwners.slice(0, 4) : [],
    evidenceRefs: Array.isArray(graphContext.evidenceRefs) ? graphContext.evidenceRefs.slice(0, 6) : [],
    specialistFocuses: Array.isArray(graphContext.specialistFocuses) ? graphContext.specialistFocuses.slice(0, 4) : [],
    specialistLenses: Array.isArray(graphContext.specialistLenses) ? graphContext.specialistLenses.slice(0, 4) : [],
    riskModifiers: Array.isArray(graphContext.riskModifiers) ? graphContext.riskModifiers.slice(0, 6) : [],
    wellnessSignals: Array.isArray(graphContext.wellnessSignals) ? graphContext.wellnessSignals.slice(0, 6) : [],
    visitSignals: Array.isArray(graphContext.visitSignals) ? graphContext.visitSignals.slice(0, 6) : [],
    triageRoutes: Array.isArray(graphContext.triageRoutes) ? graphContext.triageRoutes.slice(0, 4) : [],
    triageSignals: Array.isArray(graphContext.triageSignals) ? graphContext.triageSignals.slice(0, 4) : [],
    triageActions: Array.isArray(graphContext.triageActions) ? graphContext.triageActions.slice(0, 4) : [],
    evidenceTitles: Array.isArray(graphContext.evidenceTitles) ? graphContext.evidenceTitles.slice(0, 4) : [],
    documentTypes: Array.isArray(graphContext.documentTypes) ? graphContext.documentTypes.slice(0, 4) : [],
    documentMarkers: Array.isArray(graphContext.documentMarkers) ? graphContext.documentMarkers.slice(0, 6) : [],
    documentValues: Array.isArray(graphContext.documentValues) ? graphContext.documentValues.slice(0, 6) : [],
    riskLevels: Array.isArray(graphContext.riskLevels) ? graphContext.riskLevels.slice(0, 3) : [],
    recentFacts: Array.isArray(graphContext.recentFacts) ? graphContext.recentFacts.slice(0, 4) : [],
    summary: graphContext.summary || "No patient knowledge graph context."
  };
}

function normalizeKnowledgeGraphFacts(facts) {
  return Array.isArray(facts)
    ? facts.map((fact) => normalizeKnowledgeGraphFact(fact)).filter(Boolean).slice(0, 48)
    : [];
}

function normalizeKnowledgeGraphFact(fact = {}) {
  const source = fact && typeof fact === "object" ? fact : {};
  const type = cleanText(source.type).replace(/[^a-zA-Z0-9_-]+/g, "").slice(0, 40) || "fact";
  const key = cleanText(source.key || source.value).slice(0, 120);
  const value = compactResponseText(source.value || key, 180);

  if (!key && !value) {
    return null;
  }

  return {
    id: (cleanText(source.id) || `${type}:${key || value}:${value || key}`).slice(0, 180),
    type,
    key: key || value,
    value: value || key,
    source: cleanText(source.source || "local").slice(0, 80),
    confidence: clamp(Number(source.confidence || 0.7), 0, 1),
    lastSeenAt: cleanText(source.lastSeenAt || source.firstSeenAt)
  };
}

function normalizeGraphRiskLevel(value = "") {
  const normalized = cleanText(value).toUpperCase();

  if (!normalized) {
    return "";
  }

  if (riskRank[normalized] !== undefined) {
    return normalized;
  }

  if (normalized.includes("CRIT")) return "CRITICAL";
  if (normalized.includes("HIGH")) return "HIGH";
  if (normalized.includes("MED")) return "MEDIUM";
  if (normalized.includes("LOW")) return "LOW";

  return "";
}

function rankKnowledgeGraphFactsForMessage(facts = [], message = "") {
  const stopTokens = new Set(["about", "after", "and", "are", "ask", "before", "does", "for", "from", "give", "have", "how", "more", "should", "still", "that", "the", "they", "track", "watch", "what", "when", "with"]);
  const normalizedMessage = buildSearchText(message);
  const queryTokens = normalizedMessage
    .split(/\s+/)
    .filter((token) => token.length >= 3 && !stopTokens.has(token));

  return facts
    .map((fact) => {
      const factText = buildSearchText([fact.type, fact.key, fact.value, fact.source].join(" "));
      const termHits = queryTokens.filter((token) => factText.includes(token)).length;
      const exactValueHit = fact.value ? Number(normalizedMessage.includes(buildSearchText(fact.value))) : 0;
      const typeBoost = fact.type === "allergy" || fact.type === "safetyFlag"
        ? 4
        : fact.type === "condition" || fact.type === "medicine" || fact.type === "lab" || fact.type === "vital"
          ? 3
          : 2;
      const score = exactValueHit * 10 + termHits * typeBoost + Math.round(Number(fact.confidence || 0) * 2);

      return { fact, score };
    })
    .sort((left, right) => right.score - left.score || Number(new Date(right.fact.lastSeenAt || 0)) - Number(new Date(left.fact.lastSeenAt || 0)) || Number(right.fact.confidence || 0) - Number(left.fact.confidence || 0) || left.fact.value.localeCompare(right.fact.value))
    .slice(0, 8);
}

function normalizePatientDataRecords(records) {
  if (!Array.isArray(records)) {
    return [];
  }

  return records
    .slice(0, 12)
    .map((record) => normalizePatientDataRecord(record))
    .filter((record) => record.id || record.documentName || record.episode || record.type);
}

function normalizePatientDataRecord(record = {}) {
  return normalizeStoredPatientDataRecord(record && typeof record === "object" ? record : {});
}

function normalizeFlexibleStringArray(value, limit = 8, itemLimit = 40) {
  if (Array.isArray(value)) {
    return value.map((item) => cleanText(item).slice(0, itemLimit)).filter(Boolean).slice(0, limit);
  }

  return splitStoredRecordSignalText(value, limit).map((item) => item.slice(0, itemLimit));
}

function rankPatientRecordsForMessage(records = [], message = "") {
  const stopTokens = new Set(["and", "are", "ask", "also", "after", "before", "does", "for", "from", "give", "gives", "have", "how", "matter", "monitor", "more", "questions", "serious", "should", "still", "that", "the", "they", "track", "watch", "what", "when", "with"]);
  const normalizedMessage = buildSearchText(message);
  const queryTokens = normalizedMessage
    .split(" ")
    .filter((token) => token.length >= 3 && !stopTokens.has(token));

  if (!records.length || !queryTokens.length) {
    return [];
  }

  return records
    .map((record) => {
      const titleText = buildSearchText([record.documentName, record.episode, record.type, record.summary].join(" "));
      const tagText = buildSearchText((Array.isArray(record.tags) ? record.tags : []).join(" "));
      const clinicalText = buildSearchText(record.searchText || [record.conditions, record.vitals, record.labs, record.notes, record.followUp].join(" "));
      const medicineSignals = (Array.isArray(record.medicineNames) && record.medicineNames.length ? record.medicineNames : extractStoredRecordMedicineSignals(Array.isArray(record.medicineItems) && record.medicineItems.length ? record.medicineItems : record.medicines)).map((item) => buildSearchText(item));
      const conditionSignals = (Array.isArray(record.conditionItems) && record.conditionItems.length ? record.conditionItems : splitStoredRecordSignalText(record.conditions, 4)).map((item) => buildSearchText(item));
      const titleHits = queryTokens.filter((token) => titleText.includes(token)).length;
      const tagHits = queryTokens.filter((token) => tagText.includes(token)).length;
      const clinicalHits = queryTokens.filter((token) => clinicalText.includes(token)).length;
      const priorityHits = queryTokens.filter((token) => Array.isArray(record.prioritySignals) && record.prioritySignals.some((signal) => buildSearchText(signal).includes(token))).length;
      const exactMedicineHits = medicineSignals.filter((signal) => signal && normalizedMessage.includes(signal)).length;
      const exactConditionHits = conditionSignals.filter((signal) => signal && normalizedMessage.includes(signal)).length;
      const score = exactMedicineHits * 12 + exactConditionHits * 8 + titleHits * 4 + tagHits * 3 + priorityHits * 3 + clinicalHits * 2;

      return { record, score };
    })
    .sort((left, right) => right.score - left.score || left.record.documentName.localeCompare(right.record.documentName))
    .slice(0, 4);
}

function buildRecentVitalTrendKnowledgeSignals(recentVitals = []) {
  if (!Array.isArray(recentVitals) || !recentVitals.length) {
    return [];
  }

  const highBpCount = recentVitals.filter((reading) => Number(reading.systolic) >= 140 || Number(reading.diastolic) >= 90).length;
  const highGlucoseCount = recentVitals.filter((reading) => Number(reading.bloodSugar) >= 180).length;
  const feverCount = recentVitals.filter((reading) => Number(reading.temperatureC) >= 38).length;
  const lowOxygenCount = recentVitals.filter((reading) => Number(reading.oxygenSaturation) > 0 && Number(reading.oxygenSaturation) <= 93).length;
  const fastPulseCount = recentVitals.filter((reading) => Number(reading.heartRate) >= 100).length;

  return dedupeResponseItems([
    recentVitals.length >= 3 ? `recent saved vitals trend ${recentVitals.length} readings` : "",
    highBpCount >= 2 ? "repeated high blood pressure trend" : "",
    highGlucoseCount >= 2 ? "repeated high blood sugar trend" : "",
    feverCount >= 2 ? "repeated fever trend" : "",
    lowOxygenCount >= 1 ? "reduced oxygen trend" : "",
    fastPulseCount >= 2 ? "repeated fast pulse trend" : ""
  ]).slice(0, 5);
}

