  SCHEDULING_AGENT: ["selected record context", "record follow up", "record types", "record tags", "record conditions"],
  RECORDS_AGENT: ["selected record context", "record types", "record tags", "record conditions", "record allergies", "record medicines", "record vitals", "record labs", "record follow up"],
  CARE_TRANSITIONS_AGENT: ["selected record context", "record follow up", "record types", "record conditions", "record medicines", "record allergies", "record vitals", "record labs"],
  PHARMACY_AGENT: ["selected record context", "record medicines", "record allergies", "record conditions", "record labs", "record vitals"],
  VITALS_AGENT: ["selected record context", "record vitals", "record labs", "record conditions", "record follow up"],
  LABS_AGENT: ["selected record context", "record labs", "record vitals", "record conditions", "record follow up"],
