function resolveLocalRequirementOutput({ message, context, recordContext = {}, graphContext = {}, detectedOutput = null } = {}) {
  const output = detectedOutput && typeof detectedOutput === "object"
    ? detectedOutput
    : {
      type: "safe_answer",
      label: "Health answer",
      expectedRoute: "RAG_AGENT",
      terms: []
    };

  const genericFollowUpOutput = output.expectedRoute === "SCHEDULING_AGENT" && output.type === "appointment_plan";
  const genericGeneralOutput = output.expectedRoute === "RAG_AGENT"
    && new Set(["safe_answer", "next_step", "explanation"]).has(output.type);

  if (!genericFollowUpOutput && !genericGeneralOutput) {
    return output;
  }

  const localStatus = getLocalPatientDataStatus({ recordContext, graphContext });
  const hints = buildLocalContextIntentHints({ message, context, recordContext, graphContext });
  const searchText = buildSearchText(message);
  const explicitRouteCueMap = {
    PHARMACY_AGENT: /\b(medicine|medication|dose|tablet|pill|drug|pharmacy|prescription|side effect|missed)\b/.test(searchText),
    VITALS_AGENT: /\b(bp|blood pressure|glucose|sugar|pulse|heart rate|oxygen|spo2|temperature|reading|track|trend|log)\b/.test(searchText),
    LABS_AGENT: /\b(lab|report|result|test|marker|range|creatinine|egfr|a1c|cholesterol)\b/.test(searchText),
    SPECIALIST_DOCTOR_AGENT: /\b(specialist|doctor|kidney|heart|cardiology|nephrology|endocrinology|neurology|pulmonology|condition|symptom)\b/.test(searchText),
    INSURANCE_AGENT: /\b(insurance|claim|appeal|denial|eob|coverage|bill|billing|authorization|policy)\b/.test(searchText),
    RECORDS_AGENT: /\b(summary|record|doctor note|handoff|share|packet|timeline)\b/.test(searchText)
  };

  if (!hints.length || !localStatus.hasClinicalContext) {
    return output;
  }

  const preferredHint = [...hints].sort((first, second) => (second.confidence || 0) - (first.confidence || 0))[0] || null;
  const hintedOutput = buildLocalHintOutputForRoute(preferredHint?.route || "");

  if (!preferredHint || !hintedOutput) {
    return output;
  }

  if (genericGeneralOutput && !explicitRouteCueMap[preferredHint.route]) {
    return output;
  }

  return hintedOutput;
}

function buildRequirementProfile({ message, profile, vitals, context, singleAgentScope, answerMode, recordContext = {}, graphContext = {} }) {
  const text = buildSearchText(message);
  const detectedOutput = singleAgentScope?.interfaceName === "atlas"
    ? {
      type: "medical_atlas",
      label: "Medical atlas education",
      expectedRoute: "RAG_AGENT",
      terms: ["disease", "medicine", "treatment", "prevention", "chart", "image"]
    }
    : singleAgentScope?.interfaceName === "specialist"
      ? {
        type: "specialist_doctor",
        label: "Specialist doctor review",
        expectedRoute: "SPECIALIST_DOCTOR_AGENT",
        terms: ["disease", "specialist", "symptoms", "tests", "treatment", "prevention", "warning signs"]
      }
    : detectRequestedOutput(text, context, answerMode);
  const output = resolveLocalRequirementOutput({ message, context, recordContext, graphContext, detectedOutput });
  const detailLevel = detectRequestedDetailLevel(text, answerMode);
  const frontDoorAutoRoute = isFrontDoorAutoRouteScope(singleAgentScope);
  const expectedRoute = singleAgentScope?.enabled && singleAgentScope.route && !frontDoorAutoRoute
    ? singleAgentScope.route
    : output.expectedRoute;
  const exactnessSignals = [
    ...findKeywordMatches(text, ["only", "just", "exactly", "specific", "precise", "brief", "short", "simple"]),
    ...(singleAgentScope?.enabled
      ? [frontDoorAutoRoute ? "one-primary-agent" : "one-tab-one-agent"]
      : [])
  ];
  const missingDataPrompts = buildRequirementMissingData({ outputType: output.type, vitals, context, profile, recordContext, graphContext });
  const maxPrimaryActions = answerMode?.maxPrimaryActions || (detailLevel === "brief"
    ? 1
    : detailLevel === "detailed"
      ? 3
      : 2);
  const score = clamp(Math.round(
    72 +
      (output.type !== "safe_answer" ? 8 : 0) +
      (expectedRoute ? 7 : 0) +
      Math.min(exactnessSignals.length * 3, 9) +
      (singleAgentScope?.enabled ? 7 : 0) -
      Math.min(missingDataPrompts.length * 3, 9)
  ), 0, 99);
  const label = score >= 90
    ? "Exact requirement"
    : score >= 80
      ? "Clear requirement"
      : score >= 68
        ? "Usable requirement"
        : "Needs sharper request";

  return {
    name: "Requirement Fit Engine",
    score,
    label,
    outputType: output.type,
    outputLabel: output.label,
    expectedRoute,
    expectedAgent: routeLabel(expectedRoute),
    detailLevel,
    answerMode,
    maxPrimaryActions,
    exactnessSignals: Array.from(new Set(exactnessSignals)).slice(0, 6),
    missingDataPrompts,
    answerContract: buildAnswerContract({ output, detailLevel, singleAgentScope, answerMode }),
    noiseRules: [
      "Answer the selected request first.",
      "Avoid unrelated education, route summaries, or agent chatter.",
      "Do not diagnose, prescribe, calculate dosage, or perform live actions.",
      "Show urgent real-world care guidance when safety signals require it."
    ],
    summary: `${output.label} requested in ${answerMode?.label || detailLevel} mode; expected ${routeLabel(expectedRoute)}.`
  };
}

function normalizeAnswerMode(input = {}) {
  const answerModeInput = input.answerMode && typeof input.answerMode === "object"
    ? input.answerMode
    : null;
  const mode = normalizeSearchText(
    answerModeInput?.id
    || answerModeInput?.mode
    || answerModeInput?.label
    || input.answerMode
    || input.careMode
    || input.responseStyle
    || input.mode
  );
  const detailOverride = normalizeSearchText(answerModeInput?.detailLevel || input.detailLevel);
  const modes = {
    quick: {
      id: "quick",
      label: "Quick",
      detailLevel: "brief",
      maxPrimaryActions: 1,
      summaryStyle: "single safest next step"
    },
    deep: {
      id: "deep",
      label: "Deep Review",
      detailLevel: "detailed",
      maxPrimaryActions: 3,
      summaryStyle: "reasoned review with key context"
    },
    handoff: {
      id: "handoff",
      label: "Doctor Note",
      detailLevel: "detailed",
      maxPrimaryActions: 3,
      summaryStyle: "clinician-ready handoff summary"
    }
  };
  const selected = modes[mode] || (detailOverride === "detailed" ? modes.deep : detailOverride === "brief" ? modes.quick : modes.quick);

  return {
    ...selected,
    maxPrimaryActions: Number(answerModeInput?.maxPrimaryActions || selected.maxPrimaryActions),
    detailLevel: cleanText(answerModeInput?.detailLevel || selected.detailLevel) || selected.detailLevel,
    instruction: cleanText(answerModeInput?.instruction || answerModeInput?.responseInstruction || input.responseInstruction || "")
  };
}

